+fn build_pointer_chase(buffer_elements: usize) -> Vec<usize> {
+    if buffer_elements < 2 {
+        return Vec::new();
+    }
+
     // Create index array and shuffle using Fisher-Yates
     let mut buffer: Vec<usize> = (0..buffer_elements).collect();

